// ── Aggregation helper ──────────────────────────────────────────────
// Returns vendor-share pairs filtered by any subset of (regions, industries,
// companySize). Shares are averaged across matching segment cells, then
// optionally re-weighted by the vendor's company-size propensity, then
// renormalised to sum to 1. Each entry also includes the average confidence
// label across the contributing rows so the UI can flag thin-evidence cells.

const CONF_RANK: Record<ConfidenceLabel, number> = { "Low": 1, "Low-Medium": 2, "Medium-Low": 2, "Medium": 3, "High": 4 };
const CONF_LABEL: Record<number, ConfidenceLabel> = { 1: "Low", 2: "Low-Medium", 3: "Medium", 4: "High" };

export interface UptakeAggregateRow {
  vendor: string;
  share: number;          // 0..1, renormalised inside the filtered slice
  contributingCells: number;
  confidence: ConfidenceLabel;
}

export function aggregateUptake(opts: {
  regions?: Region[];
  industries?: Industry[];
  companySize?: CompanySize | null;
}): UptakeAggregateRow[] {
  const regions = opts.regions && opts.regions.length > 0 ? new Set(opts.regions) : null;
  const industries = opts.industries && opts.industries.length > 0 ? new Set(opts.industries) : null;
  const filtered = SEGMENT_SHARES.filter((r) => (!regions || regions.has(r.region)) && (!industries || industries.has(r.industry)));
  if (filtered.length === 0) return [];

  // Sum share + count contributing cells per vendor; track confidence rank average.
  const byVendor = new Map<string, { sum: number; cells: number; confSum: number }>();
  for (const r of filtered) {
    const cur = byVendor.get(r.vendor) ?? { sum: 0, cells: 0, confSum: 0 };
    cur.sum += r.share;
    cur.cells += 1;
    cur.confSum += CONF_RANK[r.confidence] ?? 2;
    byVendor.set(r.vendor, cur);
  }

  // Average share inside the slice → vendor mean share.
  const mean: { vendor: string; share: number; cells: number; conf: number }[] = [];
  for (const [vendor, v] of byVendor.entries()) {
    mean.push({ vendor, share: v.sum / v.cells, cells: v.cells, conf: v.confSum / v.cells });
  }

  // Optional company-size reweighting.
  if (opts.companySize) {
    const sizeMap = new Map(COMPANY_SIZE_SHARES.map((s) => [s.vendor, opts.companySize === "Large Enterprise" ? s.large : s.sme]));
    for (const m of mean) {
      const weight = sizeMap.get(m.vendor) ?? 0;
      m.share = m.share * weight;
    }
  }

  // Renormalise so the slice sums to 1 (so the UI shows share-within-this-cut).
  const total = mean.reduce((acc, m) => acc + m.share, 0);
  const out: UptakeAggregateRow[] = mean.map((m) => ({
    vendor: m.vendor,
    share: total > 0 ? m.share / total : 0,
    contributingCells: m.cells,
    confidence: CONF_LABEL[Math.round(m.conf)] ?? "Low-Medium",
  }));
  return out.sort((a, b) => b.share - a.share);
}

// Heatmap helper — returns share for one (region, industry, vendor) cell.
export function getCellShare(region: Region, industry: Industry, vendor: string): number {
  const row = SEGMENT_SHARES.find((r) => r.region === region && r.industry === industry && r.vendor === vendor);
  return row?.share ?? 0;
}
